CREATE TABLE corporate_profiles (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), owner_id UUID NOT NULL UNIQUE REFERENCES users(id), name TEXT NOT NULL, cin TEXT NOT NULL UNIQUE, description TEXT, website_url TEXT, verified_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE corporate_employees (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), corporate_id UUID NOT NULL REFERENCES corporate_profiles(id), user_id UUID REFERENCES users(id), email TEXT NOT NULL, name TEXT NOT NULL, title TEXT, status TEXT NOT NULL DEFAULT 'invited', invite_token_hash TEXT UNIQUE, invited_at TIMESTAMPTZ NOT NULL DEFAULT now(), accepted_at TIMESTAMPTZ, UNIQUE(corporate_id,email));
CREATE TABLE csr_initiatives (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), corporate_id UUID NOT NULL REFERENCES corporate_profiles(id), campaign_id UUID NOT NULL REFERENCES campaigns(id), title TEXT NOT NULL, description TEXT NOT NULL, match_percentage INTEGER NOT NULL CHECK(match_percentage BETWEEN 0 AND 500), per_employee_cap_paise BIGINT NOT NULL CHECK(per_employee_cap_paise>=0), program_cap_paise BIGINT NOT NULL CHECK(program_cap_paise>=0), status TEXT NOT NULL DEFAULT 'draft', starts_at TIMESTAMPTZ NOT NULL, ends_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE csr_match_pledges (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), initiative_id UUID NOT NULL REFERENCES csr_initiatives(id), employee_id UUID NOT NULL REFERENCES corporate_employees(id), donation_id UUID NOT NULL UNIQUE REFERENCES donations(id), amount_paise BIGINT NOT NULL CHECK(amount_paise>=0), status TEXT NOT NULL DEFAULT 'pledged', batch_id UUID, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE csr_settlement_batches (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), corporate_id UUID NOT NULL REFERENCES corporate_profiles(id), amount_paise BIGINT NOT NULL CHECK(amount_paise>0), gateway_order_id TEXT UNIQUE, gateway_payment_id TEXT UNIQUE, status TEXT NOT NULL DEFAULT 'created', created_by UUID NOT NULL REFERENCES users(id), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), settled_at TIMESTAMPTZ);
ALTER TABLE csr_match_pledges ADD CONSTRAINT csr_match_batch_fk FOREIGN KEY(batch_id) REFERENCES csr_settlement_batches(id);
ALTER TABLE payment_orders ADD COLUMN csr_initiative_id UUID REFERENCES csr_initiatives(id);
ALTER TABLE payment_orders ADD COLUMN corporate_employee_id UUID REFERENCES corporate_employees(id);
ALTER TABLE donations ADD COLUMN csr_initiative_id UUID REFERENCES csr_initiatives(id);
ALTER TABLE donations ADD COLUMN corporate_employee_id UUID REFERENCES corporate_employees(id);
